const triggerData = $('Recibir Pedido').first().json;
const corrData = $('Obtener Correlativo').first().json;

const items = triggerData.items || [];
let totalBruto = 0;

const renglones = items.map((item, index) => {
  const cant = parseInt(item.cantidad) || 0;
  const precio = parseFloat(item.precio_unitario) || 0;
  const rengNeto = cant * precio;
  totalBruto += rengNeto;

  return {
    reng_num: index + 1,
    co_art: item.codigo_producto,
    co_alma: "01", // Por defecto
    total_art: cant,
    prec_vta: precio,
    reng_neto: rengNeto
  };
});

// Suponemos 16% IVA para simplificar, se puede ajustar desde el orquestador
const iva = totalBruto * 0.16;
const totalNeto = totalBruto + iva;

// Fechas
const now = new Date();
const fecEmis = now.toISOString().split('T')[0];
now.setMonth(now.getMonth() + 1);
const fecVenc = now.toISOString().split('T')[0];

const payload = {
  fact_num: corrData.correlativo,
  nombre: "FARMACIA AMERICANA, C.A.",
  rif: "J-41074957-1",
  co_cli: triggerData.cod_cliente,
  co_ven: "VEN01",
  fec_emis: fecEmis,
  fec_venc: fecVenc,
  tasa: parseFloat(triggerData.tasa_bcv) || 36.50, // Idealmente el orquestador lo pasa
  moneda: "USD",
  tot_bruto: parseFloat(totalBruto.toFixed(2)),
  tot_neto: parseFloat(totalNeto.toFixed(2)),
  iva: parseFloat(iva.toFixed(2)),
  renglones: renglones
};

return [{ json: { payload: payload } }];
